from pathlib import Path

class Todo:
    id: int
    text: str
    done: bool = False

def __init__(self, id: int, text: str, done: bool = False):
        self.id = id
        self.text = text
        self.done = done

def mark_done(self):
        self.done = True

class TodoStore:
    def __init__(self, path: Path) -> None:
        self.path = path

    def _read(self) -> list[Todo]:
        if not self.path.exists():
            return []
        raw = json.loads(self.path.read_text())
        return [Todo(**item) for item in raw]

    def _write(self, items: list[Todo]) -> None:
        self.path.parent.mkdir(parents=True, exist_ok=True)
        self.path.write_text(json.dumps([asdict(t) for t in items], indent=2))

    def list(self) -> list[Todo]:
        return self._read()

    def add(self, text: str) -> Todo:
        items = self._read()
        next_id = (max((t.id for t in items), default=0)) + 1
        item = Todo(id=next_id, text=text)
        items.append(item)
        self._write(items)
        return item

    def mark_done(self, todo_id: int) -> Todo | None:
        items = self._read()
        for item in items:
            if item.id == todo_id:
                item.done = True
                self._write(items)
                return item
        return None

    def remove(self, todo_id: int) -> bool:
        items = self._read()
        before = len(items)
        items = [t for t in items if t.id != todo_id]
        if len(items) == before:
            return False
        self._write(items)
        return True"}
